class CategoryType(graphene.ObjectType):
    id = graphene.Int()
    name = graphene.String()
    description = graphene.String()
    products = graphene.List(lambda: ProductType)

    def resolve_products(self, info):
        return [p for p in products_data if p.category_id == self.id]

class ProductType(graphene.ObjectType):
    id = graphene.Int()
    name = graphene.String()
    description = graphene.String()
    price = graphene.Float()
    category_id = graphene.Int()
    stock = graphene.Int()
    category = graphene.Field(CategoryType)
    reviews = graphene.List(lambda: ReviewType)
    average_rating = graphene.Float()

    def resolve_category(self, info):
        return next((c for c in categories_data if c.id == self.category_id), None)

    def resolve_reviews(self, info):
        return [r for r in reviews_data if r.product_id == self.id]

    def resolve_average_rating(self, info):
        product_reviews = [r for r in reviews_data if r.product_id == self.id]
        if not product_reviews:
            return None
        return sum(r.rating for r in product_reviews) / len(product_reviews)

class ReviewType(graphene.ObjectType):
    id = graphene.Int()
    product_id = graphene.Int()
    user_name = graphene.String()
    rating = graphene.Int()
    comment = graphene.String()
