class Query(graphene.ObjectType):
    products = graphene.List(
        ProductType,
        name=graphene.String(),
        category_id=graphene.Int(),
        min_price=graphene.Float(),
        max_price=graphene.Float(),
        in_stock=graphene.Boolean()
    )
    product = graphene.Field(ProductType, id=graphene.Int(required=True))
    
    categories = graphene.List(CategoryType)
    category = graphene.Field(CategoryType, id=graphene.Int(required=True))
    
    reviews = graphene.List(
        ReviewType,
        product_id=graphene.Int(),
        min_rating=graphene.Int()
    )
    review = graphene.Field(ReviewType, id=graphene.Int(required=True))

    def resolve_products(self, info, name=None, category_id=None, min_price=None, max_price=None, in_stock=None):
        result = products_data
        
        if name:
            result = [p for p in result if name.lower() in p.name.lower()]
        
        if category_id:
            result = [p for p in result if p.category_id == category_id]
        
        if min_price is not None:
            result = [p for p in result if p.price >= min_price]
        
        if max_price is not None:
            result = [p for p in result if p.price <= max_price]
        
        if in_stock:
            result = [p for p in result if p.stock > 0]
        
        return result

    def resolve_product(self, info, id):
        return next((p for p in products_data if p.id == id), None)

    def resolve_categories(self, info):
        return categories_data

    def resolve_category(self, info, id):
        return next((c for c in categories_data if c.id == id), None)

    def resolve_reviews(self, info, product_id=None, min_rating=None):
        result = reviews_data
        
        if product_id:
            result = [r for r in result if r.product_id == product_id]
        
        if min_rating is not None:
            result = [r for r in result if r.rating >= min_rating]
        
        return result

    def resolve_review(self, info, id):
        return next((r for r in reviews_data if r.id == id), None)

class CreateReview(graphene.Mutation):
    class Arguments:
        product_id = graphene.Int(required=True)
        user_name = graphene.String(required=True)
        rating = graphene.Int(required=True)
        comment = graphene.String(required=True)

    review = graphene.Field(ReviewType)

    def mutate(self, info, product_id, user_name, rating, comment):
        new_id = max([r.id for r in reviews_data]) + 1 if reviews_data else 1
        new_review = Review(new_id, product_id, user_name, rating, comment, datetime.now())
        reviews_data.append(new_review)
        return CreateReview(review=new_review)

class UpdateProduct(graphene.Mutation):
    class Arguments:
        id = graphene.Int(required=True)
        name = graphene.String()
        description = graphene.String()
        price = graphene.Float()
        stock = graphene.Int()

    product = graphene.Field(ProductType)

    def mutate(self, info, id, name=None, description=None, price=None, stock=None):
        product = next((p for p in products_data if p.id == id), None)
        if not product:
            return None
        
        if name is not None:
            product.name = name
        if description is not None:
            product.description = description
        if price is not None:
            product.price = price
        if stock is not None:
            product.stock = stock
        
        return UpdateProduct(product=product)

class Mutation(graphene.ObjectType):
    create_review = CreateReview.Field()
    update_product = UpdateProduct.Field()

schema = graphene.Schema(query=Query, mutation=Mutation)

app.add_url_rule(
    '/graphql',
    view_func=GraphQLView.as_view(
        'graphql',
        schema=schema,
        graphiql=True
    )
)

